/**
 * Unit Tests: CSRF Protection
 * Testa geração, validação e expiração de tokens CSRF
 */

// Mock NextRequest/NextResponse
jest.mock('next/server', () => {
  class MockHeaders {
    private headers: Map<string, string>;
    constructor(init?: Record<string, string>) {
      this.headers = new Map(Object.entries(init || {}));
    }
    get(key: string) { return this.headers.get(key) || null; }
    set(key: string, value: string) { this.headers.set(key, value); }
    has(key: string) { return this.headers.has(key); }
  }

  class MockNextRequest {
    method: string;
    url: string;
    headers: MockHeaders;
    cookies: { get: (name: string) => { value: string } | undefined };

    constructor(url: string, options?: { method?: string; headers?: Record<string, string>; cookies?: Record<string, string> }) {
      this.method = options?.method || 'GET';
      this.url = url;
      this.headers = new MockHeaders(options?.headers);
      const cookieStore = options?.cookies || {};
      this.cookies = {
        get: (name: string) => cookieStore[name] ? { value: cookieStore[name] } : undefined,
      };
    }
  }

  return {
    NextRequest: MockNextRequest,
    NextResponse: {
      json: (body: unknown, init?: { status?: number }) => ({
        body,
        status: init?.status || 200,
        json: async () => body,
      }),
    },
  };
});

import { CSRFProtection, csrfProtection, generateCsrfToken, withCSRF } from '@/lib/security/csrf-protection';

describe('CSRFProtection', () => {
  let csrf: CSRFProtection;

  beforeEach(() => {
    csrf = new CSRFProtection();
  });

  describe('generateToken', () => {
    it('should generate a hex token string', () => {
      const token = csrf.generateToken('session-1');
      expect(typeof token).toBe('string');
      expect(token).toMatch(/^[a-f0-9]{64}$/);
    });

    it('should generate unique tokens for different sessions', () => {
      const token1 = csrf.generateToken('session-a');
      const token2 = csrf.generateToken('session-b');
      expect(token1).not.toBe(token2);
    });

    it('should overwrite previous token for same session', () => {
      const token1 = csrf.generateToken('session-x');
      const token2 = csrf.generateToken('session-x');
      expect(token1).not.toBe(token2);
      // Only the latest token should be valid
      expect(csrf.validateToken('session-x', token1)).toBe(false);
      expect(csrf.validateToken('session-x', token2)).toBe(true);
    });
  });

  describe('validateToken', () => {
    it('should return true for a valid token', () => {
      const token = csrf.generateToken('valid-session');
      expect(csrf.validateToken('valid-session', token)).toBe(true);
    });

    it('should return false for wrong token', () => {
      csrf.generateToken('my-session');
      expect(csrf.validateToken('my-session', 'wrong-token')).toBe(false);
    });

    it('should return false for unknown session', () => {
      expect(csrf.validateToken('nonexistent', 'any-token')).toBe(false);
    });

    it('should return false for expired token', () => {
      const token = csrf.generateToken('expiring-session');
      // Manually expire the token by manipulating internal state
      // We use the fact that CSRFProtection checks Date.now() > expiresAt
      const realDateNow = Date.now;
      Date.now = () => realDateNow() + 3600001; // 1h + 1ms past expiry

      expect(csrf.validateToken('expiring-session', token)).toBe(false);

      Date.now = realDateNow;
    });
  });

  describe('clearToken', () => {
    it('should invalidate a previously valid token', () => {
      const token = csrf.generateToken('clear-session');
      expect(csrf.validateToken('clear-session', token)).toBe(true);

      csrf.clearToken('clear-session');
      expect(csrf.validateToken('clear-session', token)).toBe(false);
    });

    it('should be safe to call for nonexistent session', () => {
      expect(() => csrf.clearToken('nonexistent')).not.toThrow();
    });
  });

  describe('generateCsrfToken (exported function)', () => {
    it('should delegate to csrfProtection singleton', () => {
      const token = generateCsrfToken('singleton-test');
      expect(typeof token).toBe('string');
      expect(token.length).toBe(64);
      expect(csrfProtection.validateToken('singleton-test', token)).toBe(true);
    });
  });

  describe('withCSRF middleware', () => {
    const { NextRequest, NextResponse } = jest.requireMock('next/server');

    const successHandler = async () => {
      return NextResponse.json({ success: true }, { status: 200 });
    };

    it('should allow GET requests without CSRF token', async () => {
      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', { method: 'GET' });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(200);
    });

    it('should allow HEAD requests without CSRF token', async () => {
      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', { method: 'HEAD' });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(200);
    });

    it('should reject POST without CSRF token', async () => {
      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', {
        method: 'POST',
        cookies: { 'session-id': 'sess-123' },
      });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(403);
      const body = await res.json();
      expect(body.error).toContain('CSRF');
    });

    it('should reject POST with invalid CSRF token', async () => {
      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', {
        method: 'POST',
        headers: { 'x-csrf-token': 'bad-token' },
        cookies: { 'session-id': 'sess-456' },
      });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(403);
    });

    it('should allow POST with valid CSRF token', async () => {
      const sessionId = 'sess-valid';
      const token = csrfProtection.generateToken(sessionId);

      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', {
        method: 'POST',
        headers: { 'x-csrf-token': token },
        cookies: { 'session-id': sessionId },
      });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(200);
    });

    it('should reject POST without session cookie', async () => {
      const wrappedHandler = withCSRF(successHandler);
      const req = new NextRequest('http://localhost/api/test', {
        method: 'POST',
        headers: { 'x-csrf-token': 'some-token' },
      });
      const res = await wrappedHandler(req);
      expect(res.status).toBe(403);
    });
  });
});
